-- Coachella 2026 (metadata): festival + 0 lineup row(s)
insert into sources (slug, name, adapter_type, adapter_key, config, trust, enabled) values (
  'coachella-2026', 'Coachella 2026 (metadata)', 'manual', 'manual_config',
  $cfg${"festival": {"slug": "coachella", "name": "Coachella", "city": "Indio", "state": "CA", "venue": "Empire Polo Club", "timezone": "America/Los_Angeles", "start_date": "2026-04-09", "end_date": "2026-04-18", "dates_estimated": true, "website_url": "https://www.coachella.com", "wikipedia_url": "https://en.wikipedia.org/wiki/Coachella_Valley_Music_and_Arts_Festival", "accent_color": "#00A878", "tags": ["multi-genre", "outdoor", "annual", "flagship", "camping", "southwest", "spring"]}}$cfg$::jsonb,
  'official', true
) on conflict (slug) do update set
  name = excluded.name, config = excluded.config,
  adapter_type = excluded.adapter_type, adapter_key = excluded.adapter_key,
  trust = excluded.trust, enabled = excluded.enabled, updated_at = now();

